// ---- Hyperlink / field text extraction --------------------------------------

#[test]
fn hyperlink_field_text() {
    // \fldrslt content should appear in extracted text.
    let text = extract("rtf2xml_hyperlink.rtf");
    assert!(text.contains("http://www.cnn.com/"), "got: {text}");
    assert!(text.contains("mailto:"), "got: {text}");
    assert!(text.contains("Hyperlink within doc"), "got: {text}");
}

// ---- Encoding / international text ------------------------------------------

#[test]
fn japanese_text() {
    let text = extract("rtf2xml_japanese.rtf");
    // Japanese text should be present (NeoOffice-generated document).
    assert!(
        text.contains("NeoOffice"),
        "expected NeoOffice reference, got: {}",
        &text[..text.len().min(200)]
    );
    // Should contain actual Japanese characters.
    assert!(
        text.chars().any(|c| ('\u{3040}'..='\u{30FF}').contains(&c)),
        "expected hiragana/katakana characters"
    );
}

#[test]
fn cp950_traditional_chinese() {
    let text = extract("rtfparserkit_cp950.rtf");
    assert!(text.contains("Test Text"), "got: {text}");
    assert!(text.contains("Copyright"), "got: {text}");
}

#[test]
fn multibyte_hex_japanese() {
    let text = extract("rtfparserkit_multibyte_hex.rtf");
    // Should decode multi-byte hex escapes into Japanese text.
    assert!(
        text.chars().any(|c| ('\u{3040}'..='\u{9FFF}').contains(&c)),
        "expected CJK characters, got: {text}"
    );
}

#[test]
fn negative_unicode_escapes() {
    let text = extract("rtfparserkit_negative_unicode.rtf");
    // File contains \u escapes with negative values for PUA codepoints.
    assert!(text.contains("F700"), "got: {text}");
}

