#[test]
fn merged_cells_real_world() {
    let mut doc = open("rtfpipe_merged_cells.rtf");
    let mut page = doc.page(0).expect("page 0");
    let tables = page.tables().expect("tables()");
    assert!(!tables.is_empty(), "should have at least one table");
    // The file has both vertical and horizontal merged cells.
    // All text is inside table cells, so check cell content.
    let all_cell_text: String = tables
        .iter()
        .flat_map(|t| &t.rows)
        .flat_map(|r| &r.cells)
        .map(|c| c.text.as_str())
        .collect::<Vec<_>>()
        .join(" ");
    assert!(
        all_cell_text.contains("merged cells"),
        "got: {all_cell_text}"
    );
}

